        Set<ListNode> visited = new HashSet<>();

        // Traverse through the list
        while (head != null) {
            // If already visited, it's the start of the loop
            if (visited.contains(head)) {
                return head;
            }

            // Mark current node as visited
            visited.add(head);

            // Move to the next node
            head = head.next;
        }

        // No cycle found
        return null;
